mapper.select:
select 
from dispatch_attempt_history
where task_id = #{taskId}
order by occurred_at desc, created_at desc
limit #{limit}

select 
from dispatch_attempt_history
where dispatch_request_id = #{dispatchRequestId}
order by occurred_at desc, created_at desc
limit #{limit}

select 
from dispatch_attempt_history
where occurred_at >= #{since}
order by occurred_at desc, created_at desc
limit #{limit}
